    const num = parseFloat(val1);
    if (!isNaN(num)) {
      const c = toCelsius(num, unit1);
      const result = fromCelsius(c, unit2);
      setState({ val2: Number.isInteger(result) ? result.toString() : result.toFixed(4).replace(/\.?0+$/, '') });
    }
  }, [val1, unit1, unit2, activeInput]);

  useEffect(() => {
